mapper.select:
select a.employee_id as employeeId from hrm_employee as a left join hrm_dept b on a.dept_id = b.dept_id left join hrm_employee_quit_info c on a.employee_id = c.employee_id where a.is_del = 0 and (a.entry_status in (1,3) or (a.entry_status = 4 and c.plan_quit_time > date_sub(#{endTime},interval 1 month ))) and entry_time <= #{endTime}
and a.employee_id in
#{employeeId}
and 1=2
group by a.employee_id

select a.employee_id as employeeId, a.employee_name as employeeName,a.expand_production,a.is_disabled as isDisabled, IF(a.post IS NULL, '无', a.post) AS post,a.job_number as jobNumber,a.dept_id as deptId,b.name as deptName, case when b.name in ('质量部','仓库','质检部','设备技术部','生产部','仓储部','研发部','工程部') then '1' else '0' end as isProduceDept, a.post_level as postLevel,a.post,a.status, case when a.post like '%经理%' or a.post like '%总监%' or a.post like '%副总%' or a.post like '%董事长%' or a.post like '%高级技师%' or a.post like '%厂长%' then 500 else 100 end fullMoney, a.become_time as becomeTime, a.full_attendance as isFullAttendance, a.entry_status as entryStatus, a.entry_time as entryDate from hrm_employee as a left join hrm_dept b on a.dept_id = b.dept_id left join hrm_employee_quit_info c on a.employee_id = c.employee_id where a.is_del = 0 and (a.entry_status in (1,3) or (a.entry_status = 4 and c.plan_quit_time > date_sub(#{endTime},interval 1 month ))) and entry_time <= #{endTime}
and a.employee_id in
#{employeeId}
and 1=2
group by a.employee_id

select b.employee_id from hrm_salary_month_emp_record a
join hrm_employee b on a.employee_id = b.employee_id and b.is_del = 0
where a.s_record_id = #{sRecordId}

    
        and a.employee_id in
        
            #{employeeId}
        
    
    
        and 1=2

select a.s_emp_record_id,a.actual_work_day,a.need_work_day, b.employee_name,b.employee_id,b.post,c.name as deptName,b.job_number,b.is_del from hrm_salary_month_emp_record a left join hrm_employee b on a.employee_id = b.employee_id left join hrm_dept c on b.dept_id = c.dept_id where a.s_record_id = #{data.sRecordId}
and b.employee_name like concat('%',#{data.employeeName},'%')
and b.job_number like concat('%',#{data.jobNumber},'%')
and b.dept_id = #{data.deptId}
